<script>		function validateForm() {			var check = true;			var error = '<div class="alert"><button type="button" class="close" data-dismiss="alert">&times;</button><strong>ERROR!</strong><br />';			// check apakah tanggal sudah terisi			if ($("#tanggal").val()=='') {				check = false;				error += 'Anda harus mengisi tanggal pembelian<br/>';			}			// check input spare part			var rowCount = $('#toro tr').length;			if (rowCount < 2) {				check = false;				error += 'Anda harus mengisi spare part apa saja yang dibeli, minimal 1 buah';			}			error += '</div>';			if (check == false) $("#error-area").html(error);			return check;		}				function deleted(id) {			var rowCount = $('#toro tr').length;			$('#t-'+id).remove();			var i = id;			for (i=id+1;i<rowCount;i++) {				$('#t-'+i).attr("id","t-"+(i-1));				$('#t0-'+i).html(i-1);				$('#t0-'+i).attr("id","t0-"+(i-1));				$('#t1-'+i).attr("id","t1-"+(i-1));				$('#t2-'+i).attr("id","t2-"+(i-1));				$('#t3-'+i).attr("id","t3-"+(i-1));				$('#t4-'+i).attr("id","t4-"+(i-1));				$('#t5-'+i).attr("id","t5-"+(i-1));				$('#t6-'+i).html('<a class="btn btn-small" href="#" onclick="deleted('+(i-1)+');">Remove</a>');				$('#t6-'+i).attr("id","t6-"+(i-1));				$('#t7-'+i).attr("id","t7-"+(i-1));				$('input[name="ids['+(i-1)+']"]').attr("name","ids["+(i-2)+"]");				$('input[name="banyak['+(i-1)+']"]').attr("name","banyak["+(i-2)+"]");				$('input[name="harga['+(i-1)+']"]').attr("name","harga["+(i-2)+"]");				$('input[name="diskon['+(i-1)+']"]').attr("name","diskon["+(i-2)+"]");			}			hitung();		}				function hitung() {			var rowCount = $('#toro tr').length;			var rowCount1 = $('#toroserv tr').length;			var toro = 0; var toro1 = 0;			var sub = 0; var sub1 = 0;			var diskon = 0; var diskon1 = 0;			var total = 0; var total1 = 0;			for (var i=2;i<=rowCount;i++) {				toro = parseInt($('input[name="banyak['+(i-2)+']"]').val())*parseInt($('input[name="harga['+(i-2)+']"]').val())-parseInt($('input[name="diskon['+(i-2)+']"]').val());				sub = parseInt(sub) + parseInt($('input[name="banyak['+(i-2)+']"]').val())*parseInt($('input[name="harga['+(i-2)+']"]').val());				diskon = parseInt(diskon) + parseInt($('input[name="diskon['+(i-2)+']"]').val());				total = parseInt(total) + toro;				$('#t5-'+(i-1)).html(toro);			}			$('#total-spare').html(sub);			$('#diskon-spare').html(diskon);			$('#total').html(total);		}		$(function() {			function log(id,label,harga,kode) {				var rowCount = $('#toro tr').length;				//check apakah sudah ada atau belum				var temu = 0;				for (var i = 2; i <= rowCount; i++) {					var j = $('input[name="ids['+(i-2)+']"]').val();					var k = parseInt($('input[name="banyak['+(i-2)+']"]').val());					if (j == id) {						$('input[name="banyak['+(i-2)+']"]').val(k+1);						temu = 1;					}				}				if (temu == 0) {					$('#toro-body').append('<tr id="t-'+rowCount+'"><td id="t0-'+rowCount+'">'+rowCount+						'</td><td id="t7-'+rowCount+'">'+kode+						'</td><td id="t1-'+rowCount+'">'+label+'<input type="hidden" name="ids['+(rowCount-1)+']" value="'+id+						'"></td><td id="t2-'+rowCount+'"><input class="input-mini" type="number" name="banyak['+(rowCount-1)+						']" value="1" onblur="hitung()"></td><td id="t3-'+rowCount+						'"><input class="input-small" type="number" name="harga['+(rowCount-1)+']" value="'+harga+						'" onblur="hitung()"></td><td id="t4-'+rowCount+'"><input class="input-small" type="number" name="diskon['+(rowCount-1)+						']" value="0" onblur="hitung()"></td><td id="t5-'+rowCount+'">0</td><td id="t6-'+rowCount+						'"><a class="btn btn-small" href="#" onclick="deleted('+rowCount+');">Remove</a></td></tr>');				}				hitung();				} 			$("#city").autocomplete({				source: function( request, response ) {					$.ajax({						url: "<?php echo base_url("pembelian"); ?>/auto_barang",						dataType: "json",						data: {							q: request.term						},						success: function( data ) {							response( data );						}					});				},				minLength: 1,				select: function( event, ui ) {					log(ui.item.value, ui.item.label1, ui.item.harga, ui.item.uac);					$("#city").val( '' );					return false;				},				focus: function( event, ui ) {					$("#city").val( ui.item.label );					return false;				},				open: function() {					$( this ).removeClass( "ui-corner-all" ).addClass( "ui-corner-top" );				},				close: function() {					$( this ).removeClass( "ui-corner-top" ).addClass( "ui-corner-all" );				}			});						$("#supplier-name").autocomplete({				source: function( request, response ) {					$.ajax({						url: "<?php echo base_url("pembelian"); ?>/auto_supplier",						dataType: "json",						data: {							q: request.term						},						success: function( data ) {							response( data );						}					});				},				minLength: 1,				select: function( event, ui ) {					$('input[name="supplier"]').val(ui.item.value);					var custdetil = '<address><strong>'+ui.item.label+'</strong><br>'+ui.item.alamat+'</address>';					$("#supplier-area").html(custdetil);					return false;				},				focus: function( event, ui ) {					$("#supplier-name").val( ui.item.label );					return false;				},			});						$("#tanggal").datepicker({				dateFormat : "yy-mm-dd",				showButtonPanel : true			});		});	</script>